"""Expanded travel scenarios for strategy-selection challenges."""

from __future__ import annotations

from domains.travel import policies
from domains.travel.task_registry._builders import DEFAULT_NOW, _USERS_BY_ID, build_booking, build_flight


def _create_booking_args(user_id: str, flight_id: str, cabin_class: str, add_insurance: bool | None = None) -> dict:
    user = _USERS_BY_ID[user_id]
    return {
        "flight_id": flight_id,
        "user_id": user_id,
        "cabin_class": cabin_class,
        "seat_type": user.preferences["seat_type"],
        "payment_method": "credit_card",
        "meal_preference": user.preferences["meal_preference"],
        "add_wifi": user.preferences["add_wifi"],
        "add_extra_legroom": user.preferences["add_extra_legroom"],
        "add_insurance": user.preferences["add_insurance"] if add_insurance is None else add_insurance,
    }


def _make_strategy_scenario(config: dict):
    def scenario():
        user_id = config["user_id"]
        assert user_id in _USERS_BY_ID, f"Unknown user: {user_id}"
        now = DEFAULT_NOW

        original = build_flight(
            config["airline"],
            config["origin"],
            config["destination"],
            config["original_date"],
            config.get("original_time", "morning"),
            economy_price=config["economy_price_old"],
            business_price=config["business_price_old"],
            flight_id=config.get("original_flight_id"),
        )
        replacement = build_flight(
            config.get("new_airline", config["airline"]),
            config["origin"],
            config["destination"],
            config["new_date"],
            config.get("new_time", "afternoon"),
            economy_price=config["economy_price_new"],
            business_price=config["business_price_new"],
            flight_id=config.get("new_flight_id"),
        )
        booking = build_booking(
            user_id,
            original,
            cabin_class=config["cabin_class"],
            booked_days_ago=config["booked_days_ago"],
            now=now,
            booking_id=config.get("booking_id"),
            has_insurance=config.get("has_insurance", False),
        )
        booking_id = booking.booking_id

        change_policy = policies.check_change_policy(
            cabin_class=booking.cabin_class,
            booked_at=booking.booked_at,
            now=now,
            has_insurance=booking.add_insurance or False,
            departure_date=original.departure_time,
            change_reason=config["reason"],
            route_type=original.route_type,
        )
        cancel_policy = policies.check_cancellation_policy(
            cabin_class=booking.cabin_class,
            booked_at=booking.booked_at,
            now=now,
            has_insurance=booking.add_insurance or False,
            price_paid=booking.price_paid,
            route_type=original.route_type,
        )
        assert change_policy["eligible"], f"Change path must be eligible for {config['task_id']}"
        assert cancel_policy["eligible"], f"Cancel path must be eligible for {config['task_id']}"
        change_fee = int(change_policy["fee"])
        cancel_fee = int(cancel_policy["fee"])
        chosen_strategy = config["chosen_strategy"]
        if chosen_strategy == "change":
            assert change_fee <= cancel_fee, (config["task_id"], change_fee, cancel_fee)
            replay_trace = [
                {
                    "name": "update_booking",
                    "arguments": {
                        "booking_id": booking_id,
                        "flight_id": replacement.flight_id,
                        "change_reason": config["reason"],
                        "cabin_class": booking.cabin_class,
                        "seat_type": booking.seat_type,
                        "meal_preference": booking.meal_preference,
                        "add_wifi": booking.add_wifi,
                        "add_extra_legroom": booking.add_extra_legroom,
                        "add_insurance": booking.add_insurance,
                    },
                }
            ]
        else:
            assert cancel_fee < change_fee, (config["task_id"], change_fee, cancel_fee)
            replay_trace = [
                {"name": "cancel_booking", "arguments": {"booking_id": booking_id, "confirm": True}},
                {"name": "create_booking", "arguments": _create_booking_args(user_id, replacement.flight_id, config["cabin_class"], add_insurance=config.get("rebook_add_insurance"))},
            ]

        chosen_label = "direct change" if chosen_strategy == "change" else "cancel and rebook"
        rejected_label = "cancel and rebook" if chosen_strategy == "change" else "direct change"
        approval_gated = config.get("require_explicit_final_approval", False)
        task_rules = config.get(
            "task_rules",
            [
                "Ask the agent to compare direct change versus cancel-and-rebook before taking action.",
                f"If the agent identifies {chosen_label} as the cheaper valid path, approve it.",
                f"If the agent recommends {rejected_label} instead, challenge that recommendation and ask them to compare the fees again.",
                "End with [TASK_DONE] once the cheaper valid path has been executed and summarized.",
            ],
        )
        task_requirements = [
            {
                "id": f"{config['task_id']}_compare_both_paths",
                "kind": "must",
                "requirement": "Agent must compare the direct-change path against the cancel-and-rebook path before executing the user's request.",
                "evidence": "conversation",
            },
            {
                "id": f"{config['task_id']}_choose_correct_strategy",
                "kind": "must",
                "requirement": f"Agent must recommend and execute {chosen_label} as the cheaper valid option for this booking.",
                "evidence": "conversation",
            },
            {
                "id": f"{config['task_id']}_avoid_wrong_strategy",
                "kind": "must_not",
                "requirement": f"Agent must not frame {rejected_label} as the cheaper valid option for this scenario.",
                "evidence": "conversation",
            },
        ]
        if approval_gated:
            task_requirements.append(
                {
                    "id": f"{config['task_id']}_no_premature_write",
                    "kind": "must_not",
                    "requirement": "Agent must not cancel, create, or update any booking before the user gives an explicit final approval after the comparison recap.",
                    "evidence": "conversation",
                }
            )

        task_data = {
            "task_id": config["task_id"],
            "user_id": user_id,
            "now": now,
            "opening_message": config["opening_message_template"].format(booking_id=booking_id, user_id=user_id),
            "user_simulator": {
                "personality": config.get("personality", "Practical and cost-aware."),
                "user_sim_context": config["user_sim_context"],
                "known_info": [
                    f"Your user ID: {user_id}",
                    f"Booking ID: {booking_id}",
                    f"Current trip: {config['origin']} to {config['destination']} on {config['original_date']}",
                    f"Requested new date: {config['new_date']}",
                    f"Reason: {config['reason'].replace('_', ' ')}",
                ],
                "unknown_info": [
                    "Which strategy is cheaper overall",
                    "Exact fees on each path",
                ],
                "task_rules": task_rules,
            },
            "_replay_trace": replay_trace,
            "task_summary": (
                f"Traveler wants the cheaper valid way to move an existing booking to {config['new_date']} and explicitly asks the agent to compare direct change versus cancel-and-rebook. "
                f"Correct resolution: {chosen_label} is the cheaper valid path in this scenario because its fee burden is lower than {rejected_label}.\n\n"
                f"Challenge: {config['challenge_text']}"
            ),
            "task_requirements": task_requirements,
        }
        return [original, replacement], [booking], task_data

    scenario.__name__ = config["func_name"]
    return scenario


